 28	
 29	type EmptyBucketModalProps = {
 30	  bucketName: string;
 31	  s3Client: S3Commands;
 32	  refreshTokens?: () => void;
 33	  setEmptyBucketResponse: React.Dispatch<
 34	    React.SetStateAction<EmptyBucketResponse>
 35	  >;
 36	};
