 38	export const getTextInputLabel = (t: TFunction, bucketName: string) => (
 39	  <Trans t={t}>
 40	    <b>
 41	      To confirm deletion, type <i>{{ bucketName }}</i>:
 42	    </b>
 43	  </Trans>
 44	);
 45	
 46	const EmptyBucketModal: React.FC<CommonModalProps<EmptyBucketModalProps>> = ({
 47	  closeModal,
 48	  isOpen,
 49	  extraProps: { bucketName, s3Client, refreshTokens, setEmptyBucketResponse },
 50	}) => {
 51	  const { t } = useCustomTranslation();
 52	  const [inputValue, setInputValue] = React.useState('');
 53	  const [inProgress, setInProgress] = React.useState(false);
 54	
 55	  const onEmpty = async (event) => {
 56	    event.preventDefault();
 57	    setInProgress(true);
 58	    let deleteResponse: DeleteObjectsCommandOutput;
 59	
 60	    try {
 61	      let isTruncated = true;
 62	      let keyMarker: string;
 63	      let versionIdMarker: string;
 64	
 65	      while (isTruncated) {
 66	        const deleteObjectKeys = [];
 67	        const searchParams = {
 68	          Bucket: bucketName,
 69	          KeyMarker: keyMarker,
 70	          VersionIdMarker: versionIdMarker,
 71	        };
 72	
 73	        // eslint-disable-next-line no-await-in-loop
 74	        const objects = await s3Client.listObjectVersions(searchParams);
 75	
 76	        if (objects?.Versions) {
 77	          deleteObjectKeys.push(
 78	            ...objects.Versions.map((object) => ({
 79	              Key: object.Key,
 80	              VersionId: object.VersionId,
 81	            }))
 82	          );
 83	        }
 84	        if (objects?.DeleteMarkers) {
 85	          deleteObjectKeys.push(
 86	            ...objects.DeleteMarkers.map((marker) => ({
 87	              Key: marker.Key,
 88	              VersionId: marker.VersionId,
 89	            }))
 90	          );
 91	        }
 92	
 93	        // eslint-disable-next-line no-await-in-loop
 94	        deleteResponse = await s3Client.deleteObjects({
 95	          Bucket: bucketName,
 96	          Delete: { Objects: deleteObjectKeys },
 97	        });
 98	
 99	        if (deleteResponse.Errors?.length > 0) {
100	          throw new Error(`${deleteResponse.Errors.length} objects failed`);
101	        }
102	
103	        isTruncated = objects.IsTruncated;
104	        keyMarker = objects.NextKeyMarker;
105	        versionIdMarker = objects.NextVersionIdMarker;
106	      }
107	    } catch (err) {
108	      // eslint-disable-next-line no-console
109	      console.error('Error while emptying bucket ', err);
110	    } finally {
111	      setInProgress(false);
112	      closeModal();
113	      setEmptyBucketResponse({
114	        response: deleteResponse,
115	        bucketName: bucketName,
116	      });
117	      refreshTokens?.();
118	    }
119	  };
120	
121	  return (
122	    <Modal
123	      title={t('Empty bucket permanently?')}
124	      titleIconVariant="warning"
125	      isOpen={isOpen}
126	      onClose={closeModal}
127	      variant={ModalVariant.medium}
128	      description={
129	        <TextContent className="text-muted">
130	          <Text component={TextVariants.p}>
131	            {t(
132	              'Emptying the bucket will permanentaly delete all objects. This action cannot be undone.'
133	            )}
134	          </Text>
135	          <Text component={TextVariants.p}>
136	            {t(
137	              'Any objects added during this process may also be deleted. To prevent adding new objects during the emptying process, consider updating the bucket policy (through CLI).'
138	            )}
139	          </Text>
140	        </TextContent>
141	      }
142	      actions={[
143	        <div>
144	          {inProgress && (
145	            <Text className="text-muted pf-v6-u-mb-sm">
146	              <em>
