148	                  'The bucket is being emptied. This may take a while to complete.'
149	                )}
150	              </em>
151	            </Text>
152	          )}
153	          <Button
154	            key="confirm"
155	            variant="danger"
156	            isLoading={inProgress}
157	            onClick={onEmpty}
158	            isDisabled={inputValue !== bucketName || inProgress}
159	          >
160	            {t('Empty bucket')}
161	          </Button>
162	
163	          <Button key="cancel" variant="link" onClick={closeModal}>
164	            {t('Cancel')}
165	          </Button>
166	        </div>,
167	      ]}
168	    >
169	      <FormGroup
170	        label={getTextInputLabel(t, bucketName)}
171	        className="pf-v6-u-mt-2xl pf-v6-u-mb-sm"
172	        fieldId="empty-bucket"
173	      >
174	        <TextInput
175	          value={inputValue}
176	          type={TextInputTypes.text}
177	          onChange={(_event, value) => setInputValue(value)}
178	          aria-label={t('Bucket name input')}
179	          validated={
180	            inputValue === bucketName
181	              ? ValidatedOptions.success
182	              : ValidatedOptions.default
183	          }
184	          placeholder={bucketName}
185	        />
186	      </FormGroup>
187	    </Modal>
188	  );
189	};
