196	type EmptyBucketAlertProps = {
197	  emptyBucketResponse: EmptyBucketResponse;
198	  setEmptyBucketResponse: React.Dispatch<
199	    React.SetStateAction<EmptyBucketResponse>
200	  >;
201	  triggerRefresh: () => void;
202	};
