204	export const EmptyBucketAlerts: React.FC<EmptyBucketAlertProps> = ({
205	  emptyBucketResponse,
206	  setEmptyBucketResponse,
207	  triggerRefresh,
208	}) => {
209	  const { s3Client } = React.useContext(S3Context);
210	  const { t } = useTranslation();
211	  const launcher = useModal();
212	
213	  if (emptyBucketResponse.response === null) return null;
214	
215	  const hasErrors =
216	    emptyBucketResponse.response?.Errors &&
217	    emptyBucketResponse.response.Errors.length > 0;
218	
219	  if (hasErrors) {
220	    return (
221	      <Alert
222	        variant={AlertVariant.danger}
223	        title={t('Cannot empty bucket')}
224	        isInline
225	        className="co-alert pf-v6-u-mb-md"
