227	          <AlertActionCloseButton
228	            onClose={() => {
229	              setEmptyBucketResponse({ response: null, bucketName: '' });
230	            }}
231	          />
232	        }
233	        actionLinks={
234	          <AlertActionLink
235	            onClick={() =>
236	              launcher(LazyDeleteObjectsSummary, {
237	                isOpen: true,
238	                extraProps: {
239	                  foldersPath: '',
240	                  errorResponse: emptyBucketResponse.response.Errors,
241	                  selectedObjects: [],
242	                },
243	              })
244	            }
245	          >
246	            {t('Check potential reasons')}
247	          </AlertActionLink>
248	        }
249	      >
250	        <p>
251	          {t(
252	            'Bucket emptying was not completed. Check for conflicts or permissions issues that are blocking this operation.'
253	          )}
254	        </p>
255	      </Alert>
256	    );
257	  }
258	
259	  return (
260	    <Alert
261	      variant={AlertVariant.success}
262	      title={t('Successfully emptied bucket ') + emptyBucketResponse.bucketName}
263	      isInline
264	      className="co-alert pf-v6-u-mb-md"
265	      actionClose={
266	        <AlertActionCloseButton
267	          onClose={() => {
268	            setEmptyBucketResponse({ response: null, bucketName: '' });
269	          }}
270	        />
271	      }
272	      actionLinks={
273	        <>
274	          <AlertActionLink
275	            onClick={() =>
276	              launcher(LazyDeleteBucketModal, {
277	                isOpen: true,
278	                extraProps: {
279	                  bucketName: emptyBucketResponse.bucketName,
280	                  s3Client,
281	                  launcher,
282	                  triggerRefresh,
283	                  setEmptyBucketResponse,
284	                },
285	              })
286	            }
287	          >
288	            {t('Delete bucket')}
289	          </AlertActionLink>
290	          <AlertActionLink
291	            onClick={() =>
292	              setEmptyBucketResponse({ response: null, bucketName: '' })
293	            }
294	          >
295	            {t('Dismiss')}
296	          </AlertActionLink>
297	        </>
298	      }
299	    >
300	      <p>
301	        {t(
302	          'Your bucket is now empty. If you want to delete this bucket, click Delete bucket'
303	        )}
304	      </p>
305	    </Alert>
306	  );
307	};
308	
309	export default EmptyBucketModal;

